          if(res.statistics[res.device_id]){
            statistics = s.split(',')
          }
          console.log(statistics.length)
          if (statistics.length > 0) {
            for (var i in statistics) {
              this.chartData.push(statistics[i])
              starttime = starttime ? starttime + res.interval_time : parseInt(res.starttime)
              this.timeData.push(this.parseTime(starttime, '{h}:{i}'))
            }
            console.log(this.timeData)
            this.$nextTick(() => {
              this.initChart()
            })
          } else {
            let txt = params.begin_time ? '选择时间段内没有数据' : '当前设备没有链接过'
            this.$message({
              message: txt,
              type: 'error'
            })
          }
        })
      }
    }
  }
